-- Seed 37 knowledge entries from 5-manager survey (6 categories)

INSERT INTO mgapp_knowledge_entries (category, question, answer, routing_contact, routing_channel, routing_department, ai_solvability, source) VALUES

-- ═══ HR (人事) ═══
('hr', '有給休暇の申請方法は？', '有給休暇はKKBの「休暇申請」メニューから申請できます。申請は取得日の3営業日前までに提出してください。上長の承認後、人事部で最終確認されます。', NULL, 'KKB', '人事部', 'ai_answerable', 'survey_manager_1'),
('hr', '育児休業の取得条件を教えてください', '育児休業は、子が1歳（最長2歳）になるまで取得可能です。取得予定日の1ヶ月前までに人事部へ申請してください。男性社員も取得できます。', '人事部 山田さん', NULL, '人事部', 'ai_supported', 'survey_manager_1'),
('hr', '通勤手当の変更手続きは？', '引越しや通勤経路変更の場合、KKBの「通勤届」から変更申請を提出してください。新しい定期代の領収書が必要です。', NULL, 'KKB', '人事部', 'ai_answerable', 'survey_manager_2'),
('hr', '健康診断の予約方法は？', '年1回の定期健康診断は人事部から案内メールが届きます。追加検査や再検査が必要な場合は、人事部 佐藤さんに連絡してください。', '人事部 佐藤さん', 'メール', '人事部', 'ai_supported', 'survey_manager_1'),
('hr', '退職手続きの流れは？', '退職に関する手続きは個別対応が必要です。まず直属の上長に相談の上、人事部との面談を設定してください。', NULL, NULL, '人事部', 'human_only', 'survey_manager_3'),
('hr', '給与明細の確認方法は？', 'KKBの「給与明細」メニューから過去12ヶ月分の明細を確認・ダウンロードできます。それ以前の明細は人事部に問い合わせてください。', NULL, 'KKB', '人事部', 'ai_answerable', 'survey_manager_2'),
('hr', '社員証を紛失した場合の対応は？', '社員証紛失時は、まず総務部 加藤さんに連絡してください。再発行には申請書と写真が必要です。再発行費用は2,000円です。', '総務部 加藤さん', '電話/メール', '総務部', 'ai_supported', 'survey_manager_4'),

-- ═══ Product (製品・業務) ═══
('product', 'KKBの操作マニュアルはどこにありますか？', 'KKBの操作マニュアルは社内ポータルの「マニュアル」セクションにあります。最新版はver3.2です。不明点はIT部門ヘルプデスクへ。', NULL, '社内ポータル', 'IT部門', 'ai_answerable', 'survey_manager_2'),
('product', '新しいプロジェクトコードの発行方法は？', '新規プロジェクトコードは経理部の承認が必要です。KKBの「プロジェクト管理」から申請し、経理部 田中さんが発行します。', '経理部 田中さん', 'KKB', '経理部', 'ai_supported', 'survey_manager_3'),
('product', '取引先との契約書テンプレートはどこ？', '契約書テンプレートは法務部の共有フォルダ（\\\\server\\legal\\templates）にあります。使用前に法務部の確認を受けてください。', '法務部', '共有フォルダ', '法務部', 'ai_supported', 'survey_manager_3'),
('product', '社内システムの開発リクエスト方法は？', 'システム開発リクエストはIT部門のチケットシステムから起票してください。要件定義書のテンプレートはIT部門ポータルにあります。', NULL, 'チケットシステム', 'IT部門', 'ai_answerable', 'survey_manager_5'),
('product', '品質管理の報告書フォーマットは？', '品質管理報告書のフォーマットは品質管理部の共有ドライブにあります。月次報告は毎月5日までに提出してください。', NULL, '共有ドライブ', '品質管理部', 'ai_answerable', 'survey_manager_4'),
('product', '顧客クレームの対応フローは？', '顧客クレームは初動対応が重要です。まず上長に報告し、品質管理部 鈴木さんと連携して対応してください。重大クレームは即日報告が必要です。', '品質管理部 鈴木さん', '電話/メール', '品質管理部', 'human_only', 'survey_manager_4'),

-- ═══ IT (情報システム) ═══
('it', 'KKBに接続できません', 'まずVPN接続を確認してください。VPNが接続済みの場合、ブラウザのキャッシュをクリアしてください。それでも解決しない場合はITヘルプデスク（内線5555）へ。', 'ITヘルプデスク', '内線5555', 'IT部門', 'ai_answerable', 'survey_manager_2'),
('it', 'パスワードを忘れた場合のリセット方法は？', 'パスワードリセットはKKBログイン画面の「パスワードを忘れた方」リンクから実行できます。登録メールアドレスにリセットリンクが届きます。', NULL, 'KKB', 'IT部門', 'ai_answerable', 'survey_manager_2'),
('it', '新しいソフトウェアのインストール申請は？', 'ソフトウェアのインストールにはIT部門の承認が必要です。ITポータルの「ソフトウェア申請」フォームから申請してください。ライセンス確認に2-3営業日かかります。', NULL, 'ITポータル', 'IT部門', 'ai_answerable', 'survey_manager_5'),
('it', 'リモートワーク用のVPN設定方法は？', 'VPN設定マニュアルはITポータルの「リモートワーク」セクションにあります。初回設定時はIT部門 中村さんがサポートします。', 'IT部門 中村さん', 'ITポータル', 'IT部門', 'ai_supported', 'survey_manager_5'),
('it', '社用PCが故障した場合は？', '社用PCの故障はITヘルプデスク（内線5555）に連絡してください。代替機の貸出が可能です。修理には通常3-5営業日かかります。', 'ITヘルプデスク', '内線5555', 'IT部門', 'ai_supported', 'survey_manager_5'),
('it', 'メールの容量が一杯になった場合は？', 'メールボックスの容量上限は5GBです。不要なメールを削除するか、アーカイブしてください。容量拡張が必要な場合はIT部門に申請してください。', NULL, NULL, 'IT部門', 'ai_answerable', 'survey_manager_2'),
('it', 'セキュリティインシデントを発見した場合は？', 'セキュリティインシデント（不審メール、情報漏洩の疑い等）を発見した場合は、直ちにIT部門セキュリティチーム（内線5556）に報告してください。', 'セキュリティチーム', '内線5556', 'IT部門', 'human_only', 'survey_manager_5'),

-- ═══ Legal (法務) ═══
('legal', 'NDA（秘密保持契約）の締結プロセスは？', 'NDAの締結は法務部を通して行います。法務部の共有フォルダにあるNDAテンプレートを使用し、法務部 高橋さんに確認を依頼してください。', '法務部 高橋さん', 'メール', '法務部', 'ai_supported', 'survey_manager_3'),
('legal', '個人情報の取り扱いルールは？', '個人情報保護方針は社内ポータルの「コンプライアンス」セクションに掲載されています。不明点は法務部に確認してください。', NULL, '社内ポータル', '法務部', 'ai_answerable', 'survey_manager_3'),
('legal', '知的財産に関する相談は？', '特許・商標・著作権に関する相談は法務部 知財チームに直接ご相談ください。発明届出書のフォーマットも法務部が管理しています。', '法務部 知財チーム', 'メール', '法務部', 'human_only', 'survey_manager_3'),
('legal', 'コンプライアンス違反を発見した場合は？', 'コンプライアンス違反の通報は、内部通報窓口（compliance@company.co.jp）または外部通報窓口を利用してください。匿名での通報も可能です。', NULL, 'compliance@company.co.jp', '法務部', 'ai_answerable', 'survey_manager_3'),
('legal', '契約書の保管期間は？', '契約書の保管期間は原則10年です。重要契約は永久保管です。電子化された契約書は法務部の文書管理システムで管理されています。', NULL, NULL, '法務部', 'ai_answerable', 'survey_manager_3'),

-- ═══ Facilities (総務・施設) ═══
('facilities', '会議室の予約方法は？', 'KKBの「施設予約」メニューから会議室を予約できます。大会議室（50名以上）は総務部の事前承認が必要です。', NULL, 'KKB', '総務部', 'ai_answerable', 'survey_manager_4'),
('facilities', '備品の購入申請方法は？', '備品購入はKKBの「購買申請」から申請してください。1万円以上の備品は上長承認が必要です。5万円以上は部門長承認も必要です。', NULL, 'KKB', '総務部', 'ai_answerable', 'survey_manager_4'),
('facilities', 'オフィスの空調に問題がある場合は？', 'オフィスの空調トラブルは総務部（内線3333）に連絡してください。ビル管理会社への連絡は総務部が行います。', '総務部', '内線3333', '総務部', 'ai_supported', 'survey_manager_4'),
('facilities', '社用車の利用方法は？', '社用車の予約はKKBの「車両予約」から行います。利用後は走行距離と給油量を記録してください。事故時は直ちに総務部に連絡してください。', NULL, 'KKB', '総務部', 'ai_answerable', 'survey_manager_4'),
('facilities', '防災訓練の予定は？', '防災訓練は年2回（6月と11月）実施されます。詳細スケジュールは総務部から1ヶ月前にメールで案内されます。', NULL, 'メール', '総務部', 'ai_answerable', 'survey_manager_4'),

-- ═══ Admin/Finance (経理・管理) ═══
('admin_finance', '経費精算の提出期限は？', '経費精算は発生月の翌月10日までにKKBから提出してください。領収書の添付が必須です。10日が休日の場合は前営業日が期限です。', NULL, 'KKB', '経理部', 'ai_answerable', 'survey_manager_1'),
('admin_finance', '出張旅費の申請方法は？', '出張旅費はKKBの「出張申請」から事前申請し、帰社後に「出張精算」で精算してください。宿泊費の上限は1泊12,000円です。', NULL, 'KKB', '経理部', 'ai_answerable', 'survey_manager_1'),
('admin_finance', '予算の追加申請方法は？', '予算の追加申請は四半期ごとに受け付けています。部門長の承認後、経理部 渡辺さんに申請書を提出してください。', '経理部 渡辺さん', 'メール', '経理部', 'ai_supported', 'survey_manager_1'),
('admin_finance', '請求書の処理フローは？', '受領した請求書はKKBの「支払申請」から登録してください。検収確認後、支払いは月末締め翌月末払いです。', NULL, 'KKB', '経理部', 'ai_answerable', 'survey_manager_1'),
('admin_finance', '書類の保管期間は？', '税務関連書類は7年、会計帳簿は10年、株主総会議事録は永久保管です。詳細は経理部の文書管理規程を参照してください。', NULL, NULL, '経理部', 'ai_answerable', 'survey_manager_1'),
('admin_finance', '決算時期の注意事項は？', '決算期（3月末）は経費精算の早期提出をお願いしています。決算スケジュールの詳細は経理部から別途案内されます。個別の調整が必要な場合は経理部長に相談してください。', NULL, NULL, '経理部', 'human_only', 'survey_manager_1');
